 78→internal fun <T : DateTimeFormatBuilder> T.outputIfNeeded(whenToOutput: WhenToOutput, format: T.() -> Unit) {
 79→    when (whenToOutput) {
 80→        WhenToOutput.NEVER -> {}
 81→        WhenToOutput.IF_NONZERO -> {
 82→            optional {
 83→                format()
