242→private fun <T> basicFormats(format: FormatStructure<T>): List<FieldFormatDirective<T>> = buildList {
243→    fun rec(format: FormatStructure<T>) {
244→        when (format) {
245→            is BasicFormatStructure -> add(format.directive)
246→            is ConcatenatedFormatStructure -> format.formats.forEach { rec(it) }
247→            is ConstantFormatStructure -> {}
248→            is SignedFormatStructure -> rec(format.format)
249→            is AlternativesParsingFormatStructure -> {
250→                rec(format.mainFormat); format.formats.forEach { rec(it) }
251→            }
252→
253→            is OptionalFormatStructure -> rec(format.format)
254→        }
255→    }
256→    rec(format)
257→}
