 37→    @Suppress("NO_ELSE_IN_WHEN")
 38→    override fun offset(format: DateTimeFormat<UtcOffset>) = when (format) {
 39→        is UtcOffsetFormat -> addFormatStructureForOffset(format.actualFormat)
 40→    }
